SELECT "Journal" AS WELineType, [Warehouse Entry].[Item No_], [Warehouse Entry].[Constant Variable Code], [Warehouse Entry].[Assortment Code], [Warehouse Entry].[Journal Batch Name] AS TestataWE, [Warehouse Entry].[Line No_] AS RigaWE, [Unique Identifier Pst_ Docnts].Code, [Warehouse Entry].[Entry No_], [Warehouse Entry].[Location Code], [Warehouse Entry].[Bin Code]
FROM ([Unique Identifier Pst_ Docnts] INNER JOIN [Warehouse Entry] ON ([Unique Identifier Pst_ Docnts].[Line No_] = [Warehouse Entry].[Line No_]) AND ([Unique Identifier Pst_ Docnts].[Journal Batch Name] = [Warehouse Entry].[Journal Batch Name])) INNER JOIN [Item Identifier] ON ([Item Identifier].[Assortment Code] = [Warehouse Entry].[Assortment Code]) AND ([Item Identifier].[Constant Variable Code] = [Warehouse Entry].[Constant Variable Code]) AND ([Item Identifier].[Item No_] = [Warehouse Entry].[Item No_]) AND ([Unique Identifier Pst_ Docnts].Code = [Item Identifier].Code);

